const adjectives=['Gentle','Quiet','Brave','Kind','Humble','Sincere','Hopeful','Patient','Grateful','Resilient','Thoughtful','Warm','Calm','Faithful','Tender','Strong','Honest','Caring','Peaceful','Wise','Modest','Bright','Loyal','Noble','Steadfast','Devoted','Joyful','Blessed','Radiant','True'];
